def CreateExtensionSetting(client, feed_items, campaign_feed, feed_item_ids):
    extension_setting = client.GetService('ExtensionSettingService').mutate({'operations': [{'operator': 'ADD', 'operand': {'campaignId': campaign_feed.campaignId, 'extensionType': 'SITELINK', 'extensionSetting': {'extensions': [{'xsi_type': 'SiteLinkFeedItem', 'feedItemId': feed_item_id, 'sitelinkText': feed_items[feed_item_id].sitelinkText, 'sitelinkUrl': feed_items[feed_item_id].sitelinkUrl, 'sitelinkFinalUrls': feed_items[feed_item_id].sitelinkFinalUrls, 'sitelinkTrackingUrlTemplate': feed_items[feed_item_id].sitelinkTrackingUrlTemplate, 'sitelinkFinalMobileUrls': feed_items[feed_item_id].sitelinkFinalMobileUrls, 'sitelinkUrlCustomParameters': feed_items[feed_item_id].sitelinkUrlCustomParameters} for feed_item_id in feed_item_ids]}}}]})
    return extension_setting